import React, { useState } from "react";
import axios from "axios";
import "./ChatBox.css";

function ChatBox() {
  const [query, setQuery] = useState("");
  const [persons, setPersons] = useState(1);

  const [response, setResponse] = useState({
    ai_response: "",
    budget: {},
    recommendations: [],
    safety: {},
    itinerary: [],
  });

  const sendQuery = async () => {
    try {
      const res = await axios.post("http://127.0.0.1:8000/chat", {
        query,
        persons,
      });

      setResponse({
        ai_response: res.data.ai_response || "",
        budget: res.data.budget || {},
        recommendations: res.data.recommendations || [],
        safety: res.data.safety || {},
        itinerary: res.data.itinerary || [],
      });
    } catch (error) {
      console.log(error);

      alert("Backend connection failed");
    }
  };

  return (
    <div className="chat-container">
      <h1>🇮🇳 India AI Travel Planner</h1>

      <p>
        Plan your budget-friendly India trip with AI recommendations,
        itinerary planning and safety analysis.
      </p>

      <textarea
        placeholder="Example: Plan a 3 day Goa trip for 2 persons under 10000 rupees"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
      />

      <input
        type="number"
        min="1"
        value={persons}
        onChange={(e) => setPersons(e.target.value)}
        placeholder="Number of persons"
      />

      <button onClick={sendQuery}>Plan Trip</button>

      <div className="response-box">

        <h2>🤖 AI Response</h2>
        <p>{response.ai_response}</p>

        <h2>💰 Budget Details</h2>
        <p>Hotel Cost: ₹{response.budget.hotel || 0}</p>
        <p>Food Cost: ₹{response.budget.food || 0}</p>
        <p>Transport Cost: ₹{response.budget.transport || 0}</p>
        <p>Total Cost: ₹{response.budget.total || 0}</p>

        <h2>📍 Recommended Places</h2>

        {response.recommendations.length > 0 ? (
          response.recommendations.map((place, index) => (
            <div key={index} className="place-card">
              <h3>{place.name}</h3>

              <p><b>City:</b> {place.city}</p>
              <p><b>State:</b> {place.state}</p>
              <p><b>Type:</b> {place.type}</p>
              <p><b>Budget:</b> ₹{place.total_budget}</p>
              <p><b>Safety Score:</b> {place.safety_score}</p>

              <p>🚆 Railway Distance: {place.railway_distance} km</p>
              <p>🚌 Bus Stand Distance: {place.bus_distance} km</p>
              <p>✈ Airport Distance: {place.airport_distance} km</p>
            </div>
          ))
        ) : (
          <p>No recommendations available</p>
        )}

        <h2>🛡 Safety Information</h2>

        <p>
          <b>Women Safety:</b>{" "}
          {response.safety.women_safety || "N/A"}
        </p>

        <p>
          <b>Child Friendly:</b>{" "}
          {response.safety.child_friendly || "N/A"}
        </p>

        <p>
          <b>Night Travel Risk:</b>{" "}
          {response.safety.night_risk || "N/A"}
        </p>

        <h2>🗓 Trip Itinerary</h2>

        {response.itinerary.length > 0 ? (
          response.itinerary.map((day, index) => (
            <p key={index}>{day}</p>
          ))
        ) : (
          <p>No itinerary available</p>
        )}
      </div>
    </div>
  );
}

export default ChatBox;
